"""
Standalone patch — writes mkt-context for Isaiah 1-4 directly.
Run: python3 scripts/zc-context-isaiah-1-4-patch.py
Note: ch 1 v1 already exists; merge_comm will skip it safely.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "1": {
    "1": "<p>Isaiah son of Amoz ministered in Jerusalem across four reigns: Uzziah (d. ~740 BCE), Jotham, Ahaz, and Hezekiah (d. ~686 BCE). The 40-year span encompasses Judah's most dangerous era: the Syro-Ephraimite crisis (735-732 BCE), the fall of the Northern Kingdom (722 BCE), and Sennacherib's campaign against Judah (701 BCE). Isaiah's name means 'YHWH is salvation' — the book's central theological claim encapsulated in the prophet's own name. Isaiah is the most quoted OT book in the NT (approximately 66 direct citations or allusions), and Luke 4:18-19 records Jesus opening the Nazareth synagogue reading with Isa 61:1-2.</p>",
    "2": "<p>'Hear, O heavens, and listen, O earth, for the LORD has spoken' — the opening of the covenant lawsuit (rib, legal dispute) genre. Calling heaven and earth as witnesses to the covenant violation follows the Deuteronomic pattern of Deut 4:26 ('I call heaven and earth as witnesses against you today') and Deut 30:19 ('I call heaven and earth to witness today that I have set before you life and death'). The covenant treaty was ratified before cosmic witnesses, and those same witnesses are summoned when one party violates it. The pattern is also in Micah 6:1-2 ('Hear, O mountains, the LORD's accusation') and Hos 4:1.</p>",
    "3": "<p>'An ox knows its owner and a donkey its master's feeding trough; but Israel does not know' — the irony is cutting: working animals demonstrate the basic loyalty to their provider that Israel withholds from YHWH. The ox and donkey were the standard team for agricultural labor in ancient Judah (Deut 22:10 prohibits yoking them together — the standard plowing pair). The image implies that the animals' instinctive recognition of provision ('who feeds me?') is more theologically perceptive than Israel's response to YHWH's centuries of covenant care. 'My people do not perceive' — the theme of Israel's cognitive failure (Isaiah will develop this into the hardening commission of 6:9-10).</p>",
    "4": "<p>'Woe to the sinful nation' (hoi goi chotel) — the first prophetic woe-oracle of Isaiah. The four-fold characterization: sinful nation, guilt-burdened people, evildoers' offspring, corrupting children. 'Holy One of Israel' (qedosh Yisrael) is Isaiah's signature epithet for YHWH, used approximately 26 times in Isaiah against 6 times in the rest of the OT. The holiness (qadosh) of YHWH is the dominant divine attribute in Isaiah (cf. the trisagion of ch. 6: 'Holy, holy, holy'). Israel's rebellion is named as 'turning their backs' — the covenant disloyalty visualized as turning away from the face-to-face relationship that characterized the Mosaic covenant.</p>",
    "5": "<p>'Why do you invite more punishment? Why do you persist in rebellion?' — the rhetorical question of YHWH addressing Israel's self-destructive persistence. 'The whole head is diseased and the whole heart is failing' — the body-politic metaphor that will be developed in vv. 6-8: the entire sociopolitical organism of Judah is sick from head to foot. 'Heart is failing' (devai, sick/faint) suggests moral exhaustion and spiritual incapacity. The nation has no internal resources for self-correction — which is why external judgment is necessary to break the cycle.</p>",
    "6": "<p>'From the sole of the foot to the top of the head there is not one healthy spot — only wounds, bruises, and open sores' — the medical diagnosis of the body politic. The head-to-foot formula for total bodily coverage is also used in Job 2:7 (Satan strikes Job with sores 'from the soles of his feet to the crown of his head'). The three injury types: petsaim (wounds from blows), chavurah (bruises/welts), and makka teriyyah (raw/festering sores). The sores are 'not cleansed or bandaged or soothed with oil' — no treatment has been applied. This is the covenant curse of Deut 28:35 applied comprehensively.</p>",
    "7": "<p>'Your land is desolate and your cities have been burned down; foreigners strip your countryside' — the historical setting for this oracle is likely Sennacherib's 701 BCE campaign, when 46 Judean cities were destroyed (according to the Taylor Prism annals) and thousands were deported. The Assyrian military practice of systematically destroying agricultural infrastructure (burning orchards, filling wells, destroying terraces) to depopulate an area is behind the 'desolate land' imagery. The Annals of Sennacherib describe Judah's countryside as stripped and Hezekiah 'like a bird in a cage' in Jerusalem.</p>",
    "8": "<p>'The daughter of Zion is left like a temporary shelter in a vineyard, like a watchman's hut in a cucumber field' — the vivid similes of abandonment. The vineyard temporary shelter (sukkah) and cucumber-field hut were flimsy seasonal structures built during harvest for watchmen; they were abandoned after harvest and collapsed. Zion, once a great city, is reduced to a ramshackle structure in the middle of a stripped field. 'Like a city under siege' (kamivtsar) — the fortified city isolated and surrounded (the Assyrian siege being the immediate reference). The daughter-Zion (bat-Tsion) personification is used for Jerusalem as the communal daughter/city throughout the Prophets.</p>",
    "9": "<p>'If the LORD of hosts had not spared us a tiny surviving remnant, we would have ended up like Sodom' — the remnant theology (she'ar, remnant/survival) that will become central to Isaiah's message (7:3 names his son Shear-jashub: 'a remnant will return'). YHWH's restraint alone prevented total destruction like Sodom and Gomorrah. Paul cites this verse (Rom 9:29) in his argument about Israel's remnant: even in judgment, YHWH preserves a seed. The comparison to Sodom/Gomorrah — the paradigmatic cities of total divine destruction (Gen 19) — sets the stakes of Judah's situation at the highest possible level.</p>",
    "10": "<p>'Hear the word of the LORD, you rulers of Sodom! Listen to the teaching of our God, you people of Gomorrah!' — having just noted in v. 9 that YHWH prevented Judah from becoming like Sodom, Isaiah immediately turns and addresses the leaders AS THOUGH they were the rulers of Sodom. The rhetorical shock is deliberate: you were spared from Sodom's fate but your conduct makes you Sodom's moral equivalent. The Sodom comparison was the most damning possible: Sodom's sin included social injustice (Ezek 16:49: 'She was arrogant, overfed, and unconcerned; she did not help the poor and needy') as well as the violence of Gen 19.</p>",
    "11": "<p>'What do I care for the great number of your sacrifices? says the LORD' — the anti-sacrifice polemic: YHWH's rejection of Israel's ritual worship because it accompanies rather than replaces social justice. This is not a wholesale rejection of sacrifice (Isaiah later assumes the continuation of temple worship in the restored Zion); it is a rejection of sacrifice + wickedness as a combination. The same polemic is in Amos 5:21-24 ('I hate, I despise your religious festivals... but let justice roll on like a river'), Micah 6:6-8 ('What does the LORD require of you? To act justly and to love mercy and to walk humbly'), and Jer 7:21-23 (the Temple Sermon).</p>",
    "12": "<p>'When you come to stand before me, who asked you to trample through my courts?' — the divine sarcasm directed at ritual attendance without moral preparation. The verb 'trample' (ramas) applied to temple pilgrimage is deliberately offensive: YHWH describes the worshipers' presence in his sanctuary as trampling (as animals trample grain). The image inverts the honor of divine access — coming to the temple is a privilege, but without righteousness it becomes an imposition. The 'courts' (chatserot) of the temple were the outer spaces where the congregation gathered.</p>",
    "13": "<p>'Stop bringing me worthless offerings; incense is detestable to me' — 'worthless offerings' (minchah shav) — the grain offering (minchah) that is shav (emptiness/vanity — the same word as 'vanity' in Ecclesiastes). Incense (qetoret), the sweet-smelling smoke that accompanied prayers in temple ritual (Ps 141:2: 'May my prayer be set before you like incense'), is called 'detestable' (to'evah, abomination) — the strongest term of divine repugnance, normally reserved for Canaanite cult practices. 'New Moons, Sabbaths, and sacred assemblies' — the entire calendar of Israel's appointed worship (Lev 23) pronounced intolerable because accompanied by evil.</p>",
    "14": "<p>'I utterly hate your new moon festivals and your appointed feasts; they have become a burden to me' — the divine burden-language: Israel's religious festivals have become oppressive weight (torach) on YHWH. The irony: the appointed feasts (mo'adim) were given precisely to celebrate YHWH's provision and covenant (Lev 23); now YHWH finds them tiresome. Jer 6:20 develops the same theme: 'What do I care about incense from Sheba or sweet calamus from a distant land? Your burnt offerings are not acceptable; your sacrifices do not please me.' Ritual without relationship = burden, not blessing.</p>",
    "15": "<p>'When you raise your hands in prayer, I will avert my eyes; your hands are soaked in blood' — hands raised in prayer (the orans posture of the ancient Near East, shown in Egyptian and Mesopotamian iconography) are the gesture of petition and praise. But the same hands are 'full of blood' (male damim) — soaked in violence, judicial murder, exploitation. The image connects worship posture to moral action: the body that kills in the marketplace cannot petition YHWH in the sanctuary. Ps 24:4 requires 'clean hands and a pure heart' for approaching YHWH. The blood-soaked hands echo the Cain narrative (Gen 4:10: 'your brother's blood cries out to me from the ground').</p>",
    "16": "<p>'Wash and make yourselves clean; remove your evil deeds from my sight; stop doing evil' — the turn from indictment to imperative: after the lawsuit (vv. 2-15), YHWH now specifies the required response. The washing language ('wash yourselves,' hirchatshu) uses the verb for ritual washing before entering the sanctuary (Exod 30:18-21; Lev 16:4), now applied to moral cleansing. The sequence: wash → be clean → remove evil acts → stop evil → learn good (vv. 16-17) is a compressed ethical curriculum. 'Remove your evil deeds from before my eyes' — YHWH's seeing/not-seeing is the theological reality: repentance makes evil deeds invisible to YHWH.</p>",
    "17": "<p>'Learn to do what is right: pursue justice, correct the oppressor, defend the orphan, take up the widow's cause' — the classic prophetic justice quartet: justice (mishpat), the oppressor (chamots, literally 'the violent one'), the orphan (yatom), and the widow (almanah). The orphan-widow pair are the paradigmatic vulnerable in ancient Israelite society: without a male protector in a patrilineal society, they had no legal standing, no land inheritance, no economic security. Their cause is the specific locus of YHWH's justice concern (Deut 10:18: 'He defends the cause of the fatherless and the widow'; Deut 27:19: cursed is he who denies justice to the foreigner, orphan, or widow).</p>",
    "18": "<p>'Come now, let us settle this between us, says the LORD: though your sins are like scarlet, they will be made white as snow' — the covenant lawsuit (rib) of vv. 2-17 reaches its resolution: YHWH offers negotiated settlement (nivachah, 'let us reason/argue/discuss the case'). The forensic legal setting gives way to a remarkable offer of full acquittal: scarlet (shani, the brilliant red dye from the scale insect Kermes, used in royal and tabernacle fabrics; Lev 14:4-6 uses scarlet thread in purification rites) made white as snow; crimson (tola'at, the worm that produces the dye) made as wool. The reversal from deep, ineradicable dye to pure white is the metaphor of divine forgiveness.</p>",
    "19": "<p>'If you are willing and obedient, you will enjoy the best the land produces' — the two-way conditional that structures the Deuteronomic covenant: obedience produces land-blessing (Deut 28:1-14) and disobedience produces land-curse (Deut 28:15-68). 'Willing and obedient' (im-tovu ve'shema'tem, if you are willing and if you hear/obey) — the double condition linking inner disposition (willing, good) to outward compliance (hear/obey — shema is the covenant listening term of Deut 6:4). 'The best the land produces' (tov ha'arets, the goodness of the land) = the agricultural abundance of the covenant blessing (Deut 8:7-10).</p>",
    "20": "<p>'But if you refuse and resist, you will be consumed by the sword — for the mouth of the LORD has spoken' — the covenant curse: refusal produces military destruction. 'Consumed by the sword' (cherev te'ukelu, the sword will eat you) — the sword as YHWH's instrument of covenant judgment is the language of Deut 28:25 and Lev 26:25. 'The mouth of the LORD has spoken' (ki pi YHWH dibber) is Isaiah's closing formula of divine authority, equivalent to the prophetic 'thus says the LORD.' It grounds the oracle in YHWH's own speech-act: what YHWH declares will come to pass because his word does not return empty (Isa 55:11).</p>",
    "21": "<p>'How the once-faithful city has become a prostitute!' — the harlot-city metaphor (zonah, a female prostitute) applied to Jerusalem opens the communal lament/accusation that runs through vv. 21-26. The faithful city (qiryah ne'emanah) has become unfaithful (zonah). The prostitution metaphor for Israel's covenant disloyalty is developed most extensively in Hosea (chs. 1-3), Jeremiah (2:20; 3:1-9), and Ezekiel (chs. 16; 23). The specific accusation here is civic/judicial corruption rather than literal sexual sin or religious harlotry. 'Once she was filled with justice (mishpat) and righteousness (tsedeq) made its home in her — but now it is murderers.'</p>",
    "22": "<p>'Your silver has turned to worthless dross; your finest wine is diluted with water' — the debasement metaphors: silver that has been separated from its lead base (sug, dross/slag) is the waste product of smelting, not the refined metal. The diluted wine (sabekah bemayim, your wine cut with water) represents the fraudulent marketplace practices of Amos 8:5-6 (cheating with scales, selling the poor for a pair of sandals). Precious metals and fine wine were the currency of honor in the ancient world; their adulteration represents the moral debasement of Jerusalem's leadership class. The metallurgical imagery will return in v. 25 (refining as divine purification).</p>",
    "23": "<p>'Your rulers are rebels and partners in crime. Every one of them loves a bribe and chases after payoffs' — the comprehensive corruption of the leadership class. Three accusations: they are rebels (sorerim, stubborn/rebellious — the covenant violation term); they are partners with thieves (chaverei gannav); they love bribes (shochad) and chase payoffs (shalmoni, the returning of favors to patrons). The bribe-accepting judge was the paradigmatic corruption in Israelite society (Exod 23:8: 'Do not accept a bribe, for a bribe blinds those who see and twists the words of the righteous'). 'They refuse to give the orphan a hearing, and the widow's case never reaches them' — the specific victims of bribe-corrupted justice are the vulnerable of v. 17.</p>",
    "24": "<p>'Therefore the Lord, the LORD of hosts, the Mighty One of Israel, declares: \"Enough — I will relieve myself of my foes\"' — the triple divine name (ha'adon, YHWH tseva'ot, avir Yisrael) is the most solemn invocation in the passage. The 'Mighty One of Israel' (avir Yisrael, literally 'Bull/Strong One of Israel') is an archaic divine epithet also in Gen 49:24 ('because of the Shepherd, the Rock of Israel, the Mighty One of Jacob') and Ps 132:2, 5. The image is of a warrior-king who has endured enough provocation and now declares action. 'I will relieve myself of my foes' — the Hebrew uses bodily language (anachemi, I will be comforted/relieved) suggesting divine emotional release through judgment.</p>",

    "25": "<p>'I will raise my hand against you and refine away your dross as with lye and remove all your impurities' — the metallurgical refining metaphor: YHWH as the smelter who applies lye (bor, potassium carbonate used in ancient silver refining to remove lead and other impurities) to purify the corrupted metal. The raised hand (ashivah yadi alayich, I will return my hand against you) signals divine action and judgment (the same gesture as the Exodus plagues). But the goal is purification, not destruction: removing the dross and impurities (bedililayich, your alloy metals) to recover the pure silver. Judgment as purification rather than annihilation is the distinctive Isaianic note.</p>",
    "26": "<p>'I will restore your judges as in former times and your counselors as in the early days. After that you will be called the City of Righteousness, the Faithful City' — the eschatological restoration oracle: YHWH will repair what the corruption of vv. 21-23 destroyed. 'Judges as in former times' (shoftayich keva'rishonah) and 'counselors as in the early days' — the model is the idealized Mosaic period or the early monarchy under David. The title the restored Jerusalem will bear: 'City of Righteousness' (ir hatsedek) and 'Faithful City' (qiryah ne'emanah) — the exact opposite of 'once-faithful city become prostitute' in v. 21. The oracle moves from indictment to restoration through refining judgment.</p>",
    "27": "<p>'Zion will be redeemed through justice (mishpat), and those among her who turn back to God, through righteousness (tsedaqah)' — the twin instruments of Zion's redemption: justice and righteousness, the same pair that characterized the ideal Jerusalem of v. 21 ('justice made its home in her') and the corrupt Jerusalem of vv. 21-23 ('they refuse to give the orphan a hearing'). Redemption (tipadeh, will be redeemed — the root pdh, ransoming a slave or captive) will come through the social practices that should have prevented judgment. The penitents ('those who turn back') are the remnant (implied) who will populate the restored city.</p>",
    "28": "<p>'But rebels and sinners will be crushed together, and those who abandon the LORD will be utterly destroyed' — the two-way division that closes the chapter: those who respond to YHWH's call (v. 18-19) are redeemed; rebels/sinners/apostates are destroyed. 'Rebels' (poshe'im, covenant-breakers) and 'sinners' (chatta'im, moral offenders) and 'those who abandon the LORD' (ozeve Yhwh) — three ways of naming the covenant-disloyal. 'Utterly destroyed' (yiklu, they will be consumed/finished) is the language of total consumption, parallel to the fire of v. 31.</p>",
    "29": "<p>'For you will be put to shame over the sacred oak trees you desired, and humiliated over the ritual gardens you chose' — the Canaanite cult practices: 'sacred oak trees' (elim, terebinths/oaks — the ha'elim, the strong trees under which Baal and Asherah were worshiped at the high places) and 'ritual gardens' (ganot, gardens for fertility cult worship). The practice of planting sacred gardens for Asherah worship and conducting fertility rites under large trees is attested throughout the prophets (Hos 4:13: 'They sacrifice on the mountaintops and burn offerings on the hills, under oak, poplar, and terebinth, because their shade is good'). 'Shame' and 'humiliation' — the honor-shame reversal for the idol-worshipers.</p>",
    "30": "<p>'You will be like an oak tree with withering leaves, and like a garden with no water' — the fitting punishment matches the crime: those who worshiped under the sacred oaks become like a withering oak; those who cultivated ritual gardens become like a garden without water. The curse of Deut 28:23-24 (bronze sky, powdery earth, no rain) is applied specifically to the practices the worshipers chose. The desiccated garden is the antithesis of Ps 1:3 ('a tree planted by streams of water that yields its fruit in season and whose leaf does not wither') — the wicked become the anti-tree rather than the blessed tree.</p>",
    "31": "<p>'The powerful will become like tinder, and their deeds like a spark; both will burn together and no one will put out the fire' — the closing fire image. 'The powerful' (hechazon, the strong one) become combustible material (ne'orts, tinder/hemp-like fiber); their deeds (po'olo, his work) become the spark (nitstots) that ignites it. The combination of the powerful person and their evil deeds produces unstoppable self-consuming fire — divine judgment that no human intervention can extinguish (contrast the intercession of Amos 7:2-5 where Amos successfully pleads for YHWH to relent; here no such intercession is possible). The chapter that opened with covenant lawsuit closes with unquenchable fire.</p>"
  },
  "2": {
    "1": "<p>Isaiah 2 opens with a second superscription ('the word that Isaiah son of Amoz saw') — suggesting this may have originally been an independent oracle collection, or that the chapter introduces a new section. The verb 'saw' (chazah) is the visionary term for prophetic reception (cf. the superscription of 1:1: 'the vision that Isaiah saw'). The oracle that follows (vv. 2-4) is among the most famous in the entire OT and is found in nearly identical form in Micah 4:1-3, raising the question of which prophet quoted which (or whether both drew on a common temple liturgy).</p>",
    "2": "<p>'In the last days, the mountain where the LORD's house stands will be established as the highest of all mountains' — 'in the last days' (be'acharit hayyamim, in the end of the days) is the eschatological formula that introduces the vision's temporal frame: this is not a prediction for the immediate future but a picture of the world's ultimate destination. Zion as the highest mountain: in Canaanite mythology, Baal's divine mountain was Zaphon (the far north), the meeting place of the gods. Isaiah's oracle relocates the cosmic mountain to Zion (YHWH's actual dwelling) and declares it will be exalted above all. 'All nations will stream toward it' (venaharu elav kol-hagoyim) — the universal pilgrimage that reverses Babel's scattering.</p>",
    "3": "<p>'Many peoples will come and say: \"Come, let us go up to the mountain of the LORD, to the house of the God of Jacob, that he may teach us his ways\"' — the nations voluntarily making pilgrimage to Zion to receive instruction (torah) from YHWH is a reversal of the Deuteronomic pattern: normally Israel receives Torah at Sinai and the nations do not. Here the nations come to Jerusalem to receive YHWH's teaching — making Zion the new Sinai from which divine instruction radiates universally. 'For the teaching will go out from Zion and the word of the LORD from Jerusalem' — the torah-word pairing makes explicit: Zion = eschatological Sinai. Rev 21:24-26 (the nations bringing their glory into the New Jerusalem) reflects this vision.</p>",

    "4": "<p>'He will settle disputes between nations and arbitrate for many peoples. Then they will beat their swords into plowshares and their spears into pruning hooks' — YHWH as international arbiter (shaphat, judge) and arbitrator (yakiach, adjudicate/correct) makes war unnecessary: if YHWH settles disputes, the nations need no weapons. The specific agricultural conversions: cherev (swords) into ittim (plowshares — iron blades for breaking ground); chanit (spears/lances) into mazmerat (pruning hooks for vineyards). The conversion from military to agricultural implements symbolizes the transformation of energy from killing to growing. Joel 3:10 deliberately reverses this oracle ('beat your plowshares into swords') for the judgment-day context — assuming Isaiah's vision as its point of departure.</p>",
    "5": "<p>'Come, house of Jacob, let us walk in the light of the LORD!' — the transitional call that moves from the eschatological vision (vv. 2-4) to the present indictment (vv. 6-22). The logical inference: since YHWH's light will one day illuminate all nations, Israel should walk in that light now. The 'light of the LORD' (be'or Yhwh) connects to the later Isaianic imagery of the Servant as 'a light for the nations' (42:6; 49:6) and to 60:1-3 ('Arise, shine, for your light has come... the nations will come to your light'). The call 'Come' (leku) is the same invitation extended to the nations in v. 3 — inviting Israel to join the eschatological pilgrimage proactively.</p>",
    "6": "<p>'For you, LORD, have rejected your people, the house of Jacob, because they have adopted practices from the east and practice divination like the Philistines, and they make agreements with foreigners' — the specific covenant violations: eastward practices (qedem, Mesopotamian divination, astrology, and magic), Philistine divination (qosmim kafelishtim, same as Philistines who consulted Baal-Zebub, 2 Kgs 1:2-3), and 'agreements with foreigners' (yashpequ beyalde nocharim, making covenants with the sons of foreigners — political alliances that substituted foreign military power for YHWH-trust). Ahaz's alliance with Assyria against Syria/Israel (2 Kgs 16:7-8) is the paradigm case Isaiah opposed.</p>",
    "7": "<p>'Their land is full of silver and gold with no end to their treasures; their land is full of horses with no end to their chariots' — the triple 'full' (male'ah) indictment: silver/gold, horses/chariots, idols (v. 8). These are precisely the three things Deut 17:16-17 prohibits the king from multiplying: 'He must not acquire great numbers of horses for himself... He must not accumulate large amounts of silver and gold.' The military equipment (horses, chariots) = dependence on Egyptian military technology (Isa 31:1-3 develops this: woe to those who go down to Egypt for horses). Wealth accumulation and military power are the alternatives to YHWH-trust.</p>",
    "8": "<p>'Their land is full of idols; they worship what their own hands have made, what their own fingers have fashioned' — the idol polemic: the gods of the nations are human artifacts (made by hands and fashioned by fingers). Isaiah develops the most sustained and devastating idol polemic in the OT (44:9-20: the craftsman who uses half the tree for firewood and half to make a god). The satire rests on the premise that a divine being who depends on human craftsmanship for its existence cannot rescue its creators (Isa 46:1-2: Bel and Nebo, Babylonian gods, must be carried as cargo, unable to carry their people).</p>",
    "9": "<p>'Mankind is brought low and every person humbled — do not forgive them!' — the anticipation of the Day of the LORD judgment (which vv. 10-21 describe): both the common person (adam, generic humanity) and the great person (ish, the individual of significance) will be humbled. 'Do not forgive them!' (al-tissa lahem, do not lift/pardon for them) is a prophetic intercessory-renunciation formula — Isaiah is told not to intercede for judgment's reversal (cf. Jer 7:16: 'Do not pray for this people or offer any plea or petition for them'). The refusal to intercede marks a point of no return in the covenant relationship.</p>",
    "10": "<p>'Hide yourself in the rocky cliffs and bury yourself in the dust from before the terrifying presence of the LORD and the splendor of his majesty' — the call to hiding before the theophanic approach of YHWH. The rocky cliffs (tsur, bedrock) and dust (afar) as hiding places evoke the cave in which Elijah hid during the Horeb theophany (1 Kgs 19:9-13). The 'terrifying presence' (pachad Yhwh) and 'splendor of his majesty' (hadar ge'ono) are the physical manifestations of the holy warrior YHWH approaching in judgment. Revelation 6:15-16 echoes this verse: 'They called to the mountains and the rocks, \"Fall on us and hide us from the face of him who sits on the throne.\"'</p>",

    "11": "<p>'The arrogant gaze of mankind will be brought low and human pride will be humbled; on that day the LORD alone will be exalted' — 'the arrogant gaze' (einei gavhut ha'adam, the haughty eyes of man) is the specific physiognomy of pride: the lifted head and elevated gaze of the person who considers himself above others. The Proverbs list 'haughty eyes' as the first of the seven things YHWH hates (Prov 6:17). The Day-of-the-LORD formula appears here for the first time in the chapter: 'on that day' (bayyom hahu) the polarity reverses — human elevation becomes humiliation; divine exaltation is absolute. This is the eschatological reversal of the Magnificat (Luke 1:51-52: 'He has scattered those who are proud in the inmost thoughts of their hearts').</p>",
    "12": "<p>'For the LORD of hosts has appointed a day against everything proud and exalted, against everything lifted high — it will be humbled' — the 'day of the LORD of hosts' (yom le-Yhwh tseva'ot) introduces the comprehensive list of targets in vv. 12-16. The divine warrior YHWH has set his appointment (yom, day; mo'ed, appointed time) against every manifestation of created greatness. 'Everything proud and exalted' (kol-ge'eh verum) and 'everything lifted high' (kol-nissa) — the Hebrew uses three synonyms for elevation/pride to indicate the totality of YHWH's judgment against human and natural pretension to greatness.</p>",
    "13": "<p>'Against all the towering cedars of Lebanon and all the oaks of Bashan' — the first specific targets: Lebanon's cedars (erez halevavon) and Bashan's oaks (allone habashan). The cedars of Lebanon were the largest and most impressive trees in the ancient Near Eastern world — used for temple construction (1 Kgs 5:6-10), royal palaces (1 Kgs 7:2), and as a symbol of might and pride (Ps 92:12: 'the righteous flourish like a palm tree and grow like a cedar in Lebanon'). Bashan's oaks were famous for their strength (Ezek 27:6; Amos 2:9). Natural greatness — the tallest, strongest trees — falls under the Day of the LORD.</p>",
    "14": "<p>'Against all the high mountains and against all the elevated hills' — the geological landscape of pride: high mountains (harim haramim, the lifted-up mountains) and elevated hills (hageva'ot hanissa'ot, the exalted hills). In the ancient cosmology, mountains were sacred high places where the divine council met (Isa 14:13: 'I will ascend to the heavens... I will sit enthroned on the mount of assembly'; the Baal mythology of Ugarit set the divine council on Mount Zaphon). The elevated terrain that was associated with divine power will itself be humbled — no natural high place survives YHWH's universal Day.</p>",
    "15": "<p>'Against every tall tower and against every fortified wall' — the human architectural achievements: tall towers (kol-migdal gavoah, every tower of height) and fortified walls (kol-chomah beturah, every defended/cut wall). Towers and walls were the technology of power in the ancient world — the Assyrian siege-ramp system was specifically designed to overcome such structures (2 Kgs 19:32). The tower of Babel (Gen 11:4: 'a tower that reaches to the heavens') is the paradigm of human architectural pride meeting divine opposition. Military fortifications built as alternatives to YHWH-trust (cf. Isa 22:8-11: 'You built a reservoir between the two walls... but you did not look to the One who made it') fall on the Day of the LORD.</p>",
    "16": "<p>'Against all the merchant ships of Tarshish and against all their prized vessels' — 'ships of Tarshish' (aniyyot tarshish) were the large, ocean-going merchant vessels (Tarshish = possibly Tartessus in Spain, the far western limit of the ancient Mediterranean world). Solomon built ships of Tarshish for the Ophir trade (1 Kgs 9:26-28; 10:22). The Phoenician-Israelite maritime commerce represented the height of economic power and international reach. 'Prized vessels' (kol-sekiyyot hachemdah, all the delightful/beautiful crafts) — the luxury goods of Mediterranean trade. Commercial power falls alongside military power on the universal Day.</p>",
    "17": "<p>'Human pride will be brought low and human arrogance will be humbled; on that day the LORD alone will be exalted' — the exact repetition of v. 11 forms an inclusio for the Day-of-the-LORD list (vv. 12-16). The repetition is deliberate liturgical reinforcement: before and after the comprehensive catalog of pride-objects (trees, mountains, towers, ships), the theological point is restated: the Day will simultaneously humble all human and natural greatness while exalting YHWH alone. The exclusive exaltation of YHWH on that day is the positive eschatological goal; the humbling of everything else is its necessary corollary.</p>",
    "18": "<p>'And the idols will completely disappear' — brief but total: the idols (ha'eliylim, the nonentities/worthless ones — a play on elohim, gods, by adding the diminutive suggesting their nothingness) will 'completely disappear' (chalilah ya'avoru, will pass away entirely). The Day of the LORD that humbles the great trees and mountains also eliminates the idols that were worshiped under them (v. 8) and in their shade (cf. 1:29). The idol polemic connects: what human hands make (v. 8) disappears on YHWH's Day.</p>",
    "19": "<p>'People will go into the caverns of the rocks and the holes of the ground to escape the terrifying presence of the LORD and the splendor of his majesty, when he rises to make the earth tremble' — almost identical to v. 10, the panic-flight to caves is now narrated (rather than commanded). 'When he rises to make the earth tremble' (bekumoh la'arats lehachrid) — the theophanic approach of YHWH causes seismic disturbance (the connection between divine approach and earthquake is in Ps 18:7; 68:8; Hab 3:6). The phrase will reappear in Amos 8:8 and Nah 1:5. Revelation 6:15-17 draws directly on this verse for the sixth-seal earthquake.</p>",
    "20": "<p>'On that day people will throw away their silver idols and gold idols, which they made for themselves to worship, flinging them to the moles and the bats' — the dramatic abandonment of the idols: thrown to the moles (chafar perot, digging moles or possibly prairie mice) and bats (atalef, the bat) — creatures of dark, underground, and hidden places. The precious metals wasted on idol-making (silver and gold from v. 7) are now flung to vermin. The irony is acute: the craftsmen who made the idols from precious materials (v. 8) now throw them away in panic. The idols provide no refuge when YHWH appears — only his mountain-caves protect (v. 19, sarcastically).</p>",
    "21": "<p>'They will hide in the clefts of the rocky crags and the fissures of the cliffs to escape the terrifying presence of the LORD and the splendor of his majesty, when he rises to make the earth tremble' — the third repetition of the hiding-from-YHWH motif (vv. 10, 19, 21) creates a litany of panic. The threefold repetition is a rhetorical device of intensification (the same structure as the Day-of-the-LORD catalog in vv. 12-17). The rocky crags and cliffs form a grotesque shelter: the same rocks that the worshipers fled to from YHWH's face (Exod 33:22: YHWH sheltered Moses in the cleft of a rock to show his glory) now become hiding places from that same glory.</p>",
    "22": "<p>'Stop trusting in mere mortals, who have nothing but a breath in their nostrils — what are they really worth?' — the chapter's conclusion draws the practical inference from the Day-of-the-LORD vision: if all human greatness will be humbled (trees, mountains, towers, ships, idols), trust in human power is foolish. 'Breath in their nostrils' (neshamah be'appo, breath in his nose) echoes Gen 2:7 (YHWH breathed into man's nostrils the breath of life) — the fragility of human life is its breath-dependence. 'What are they really worth?' (bameh necheshav hu, in what is he to be accounted?) — the final rhetorical question diminishes all human pretension to zero.</p>"
  },
  "3": {
    "1": "<p>Isaiah 3 opens the oracle of social collapse: YHWH is about to remove the entire infrastructure of Judean society. 'The Lord, the LORD of hosts, is about to remove from Jerusalem and from Judah every kind of support' — the double divine name (ha'adon, YHWH tseva'ot) signals solemn divine declaration. 'Support' (mash'en umash'enah, masculine and feminine of the same root) — the two genders of the word for 'support/staff' indicate comprehensive removal: both masculine and feminine categories of societal support. 'Every support of bread and every support of water' — the material prerequisites of life and civilization, now threatened by siege and famine (the immediate Assyrian context).</p>",
    "2": "<p>'The warrior and the soldier, the judge and the prophet, the diviner and the elder' — the first tier of the social leadership catalog being removed. The warrior (gibbor, the hero/mighty man) and soldier (ish milchamah, man of war) represent military security. The judge (shofet) and prophet (navi) represent judicial and divine guidance. The diviner (qosem qsamim, one who divines divinations) is notable — divination was technically prohibited (Deut 18:10) yet apparently performed within Israelite society and relied upon for decision-making. The elder (zaqen) represents the traditional community wisdom structure. All removed together suggests catastrophic leadership vacuum.</p>",
    "3": "<p>'The captain of fifty and the man of standing, the counselor and the skilled artisan and the expert enchanter' — the second tier. Captain of fifty (sar chamishim) was a standard military rank (2 Kgs 1:9-14; 1 Sam 8:12). 'Man of standing' (nesi panim, literally 'one who is lifted up in face/rank') = a person of social distinction. The counselor (yo'ets) advised leadership on policy. The skilled artisan (chakham charashim, wise craftsman) — the technical expert who builds and creates (the category of Bezalel in Exod 31:3-5). The 'expert enchanter' (nebon lachash, understanding of whisper-magic) represents one who could neutralize harmful magic — a common social need in the ANE world.</p>",
    "4": "<p>'I will make youths their rulers, and infants shall govern them' — the ultimate social humiliation: rule by those too young to have wisdom or experience. 'Youths' (ne'arim, adolescents) and 'infants' (ta'alulim, children/capricious ones) as rulers inverts the entire gerontocratic structure of ancient Israelite society, where wisdom was accumulated through age and elder counsel was authoritative (Job 12:12: 'Is not wisdom found among the aged? Does not long life bring understanding?'). Cf. Eccl 10:16: 'Woe to the land whose king is a servant and whose princes feast in the morning.' Leadership by those incapable of self-governance produces collective catastrophe.</p>",
    "5": "<p>'The people will oppress one another, everyone against his neighbour; the young will be arrogant toward the old, and the worthless toward the honourable' — the breakdown of social hierarchy produces horizontal violence. 'Oppress one another' (yinhagu ha'am ish beish, the people will behave oppressively, each against the other) — the covenant community tears itself apart when the common orientation toward YHWH is lost. The specific inversions: young (na'ar) against old (zaqen), and 'worthless' (niqqaleh, the despised) against 'honourable' (nichbad, the honored) — the honor-shame structure that maintains social cohesion is reversed. This is the Deuteronomic curse of Deut 28:43-44 fulfilled.</p>",
    "6": "<p>'A man will seize his own brother in their father's house and say: \"You have a robe; be our leader\"' — the desperation for leadership reaches the point of coercion within families. 'You have a robe' (simlah lecha, you have a garment) — minimal clothing is now the qualification for leadership: in a collapsed economy, the possession of basic clothing makes someone relatively wealthy. The 'heap of ruins' (michshelah, stumbling/ruin-heap) that the reluctant leader is asked to govern under — even the infrastructure of the city is collapsing. The word michshelah is related to michshol (stumbling block), suggesting the city has become a trap for its own inhabitants.</p>",

    "7": "<p>'But on that day he will protest: \"I am no healer; in my house there is no bread and no robe; do not make me a leader of the people\"' — the reluctant refusal. 'I am no healer' (lo echbesh) — literally 'I am not a bandager/binder of wounds' — refusing the role of wound-binder echoes ch. 1:6 (the nation's wounds are not 'cleansed or bandaged'). No bread, no robe — the two basic necessities that even a minimal leader would need to provide. The complete collapse of patronage: the patron-client system requires patrons who have something to give; when no one has resources, the entire social web disintegrates.</p>",

    "8": "<p>'For Jerusalem has stumbled and Judah has fallen, because in word and deed they have rebelled against the LORD, defying his glorious presence' — the theological diagnosis of the social collapse: not mere political misfortune but covenant rebellion (marah, to be rebellious — the exodus-wilderness term for Israel's rebellion against YHWH). 'In word and deed' (bemar'aseh udevaro, in their deeds and their words) — comprehensive rebellion covering both action and speech. 'Defying his glorious presence' (lahalot einei chevodo, to challenge the eyes of his glory) — the specific affront is before YHWH's eyes: the social wickedness is not hidden but performed in the presence of the divine glory, which demands their acknowledgment.</p>",
    "9": "<p>'The expression on their faces testifies against them; they flaunt their sin like Sodom and do not conceal it' — 'the expression on their faces testifies against them' (hakkarat penihem aneta bam, the recognition of their faces testifies against them) — their faces display their guilt publicly. 'They flaunt their sin like Sodom' (vechatat sedom higidu, they have told/declared their sin like Sodom) and 'do not conceal it' (lo chicedu, they have not hidden) — Sodom's notorious openly public display of immorality (Gen 19:4-9: all the men of the city demanding Lot's guests 'so we can have sex with them') becomes the standard for Jerusalem's brazen wickedness. 'Woe to them! For they have brought disaster on themselves' — the self-inflicted nature of covenant curse.</p>",
    "10": "<p>'Tell the righteous that it will go well for them, for they shall enjoy the fruit of their actions' — the prophetic tradition of two-way justice: the righteous will receive the fruit of their righteous actions (tov, good) = Deut 28:1-14 blessings for obedience. The righteous (tsadiq) person who pursues what YHWH requires (cf. 1:16-17) receives proportional good. The 'fruit of their actions' (peri ma'allehem, fruit of their deeds) is the agricultural metaphor for moral causality: actions produce outcomes that match their character, as a tree's fruit matches its nature.</p>",
    "11": "<p>'Woe to the wicked! It will go badly for him, for what his hands have done will be done to him in return' — the inverse: the wicked (rasha) receives ra (evil/bad) = Deut 28:15-68 curses for disobedience. 'What his hands have done will be done to him in return' (gemul yadav ye'aseh lo, the recompense of his hands will be done to him) — the lex talionis extended to moral causality: the hands that executed wickedness become the measuring instruments of the return. The divine law of sowing and reaping (Gal 6:7-8: 'a man reaps what he sows') operates both positively (v. 10) and negatively (v. 11).</p>",
    "12": "<p>'My people — their oppressors are children, and women rule over them. O my people, your guides mislead you' — the reversal of proper authority: children (me'olel, suckling children/infants) and women as oppressors is the social inversion prophesied in v. 4. In the patriarchal structure of ancient Judah, rule by those normally excluded from political power (children, women) is the mark of social collapse. 'Your guides mislead you' (umevasherichem meta'im, your guides cause you to wander/err) — the leadership is actively misdirecting the people. 'They have confused the path you should walk' (derekh archo bil'u, the path of your ways they have swallowed up) — the covenant path (derekh, the Deuteronomic 'way') is obliterated by corrupt guidance.</p>",
    "13": "<p>'The LORD has taken his stand to bring a charge; he stands to render judgment on the peoples' — the divine judge standing in court. 'YHWH has taken his stand' (nitsav Yhwh laruv, YHWH stands to argue/dispute) signals the transition to the covenant lawsuit (rib) against the leaders, parallel to 1:2-20. YHWH standing to judge ('amad leshafet, standing to judge) is the posture of the judge rendering verdict in the assembly. 'On the peoples' (ammim, the populace as a whole, or possibly 'peoples' in the plural) — the lawsuit is directed at the national leadership whose conduct affects all the people.</p>",
    "14": "<p>'The LORD brings his case against the elders and leaders of his people: \"You have plundered the vineyard; the goods stolen from the poor fill your houses\"' — the vineyard (kerem) plundered by the elders and leaders: the vineyard is a recurring Isaianic metaphor for Israel (fully developed in Isa 5:1-7: 'My loved one had a vineyard on a fertile hillside... he expected a crop of good grapes, but it yielded only bad fruit'). Here the leaders have plundered their own vineyard — extracted wealth from the people they should have protected. 'The goods stolen from the poor fill your houses' (gezalat he'ani bevateichem, the plunder of the poor is in your houses) — the specific crime: housing stolen goods in the elite's own residences.</p>",

    "15": "<p\">'What do you think you are doing, crushing my people and grinding the faces of the poor into the dust?' declares the Lord GOD of hosts' — 'grinding the faces of the poor into the dust' (ufenei aniyyim techenu, and the faces of the poor you grind) is one of the most graphic images of oppression in the prophets. The mill-grinding metaphor: the poor are treated as raw material to be processed for the elite's benefit. 'My people' (ammi, first-person divine ownership) — YHWH owns these people; their oppression is an offense against the divine property owner. Amos 2:6-8 and 8:4-6 develop the same specific charges against the economically powerful who exploit the poor.</p>",
    "16": "<p>'The LORD said: Because the women of Zion are proud, walking with their heads held high and casting seductive glances, prancing along and jingling their ankle ornaments' — the oracle against Zion's elite women (the wives and daughters of the corrupt leadership of vv. 13-15). The charges are embodied pride: 'heads held high' (metansef ha-tsavar, stretched-out neck), 'seductive glances' (mesaqerot einayim, eyeing/flirting with eyes), 'prancing along' (telakhnah tapof, mincing/tripping along), and 'jingling ankle ornaments' (be'aglatam tanaknah, with their ankle ornaments tinkling). The conspicuous consumption and display of wealth while the poor are ground like grain (v. 15) is the social contradiction the oracle exposes.</p>",
    "17": "<p>'The Lord will afflict the scalps of the daughters of Zion with sores, and the LORD will expose their shame' — the fitting punishment: the crowned/coiffed heads that were held high (v. 16) will be afflicted with sores and baldness (gachat, scabs on the scalp). 'The LORD will expose their shame' (ervatam ye'areh, he will uncover their nakedness) — the shaming reversal: those who displayed themselves seductively will be exposed in humiliation. The logic is covenantal: Deut 28:27 threatens skin diseases as covenant curse. Ezekiel 16 develops the same logic against Jerusalem as the adorned but unfaithful woman stripped of her ornaments.</p>",
    "18": "<p>'In that day the Lord will remove their ornamental anklets, headbands, and crescent necklaces' — the beginning of the famous catalogue of 26 luxury items to be removed (vv. 18-23). 'In that day' (bayyom hahu) marks the eschatological reversal. Anklets (ha'ekes, ankle ornaments that created the jingling sound of v. 16), headbands (hashevi'im, the hair-nets or step-chains between anklets), and crescent necklaces (hasaharonim, the little moon-shaped pendants — associated with lunar deity devotion and worn as protective amulets). The catalogue documents the extent of the luxury goods trade and the wealth concentration in Jerusalem's elite class during the 8th-century BCE economic boom.</p>",
    "19": "<p>'The earrings, the bracelets, and the veils' — earrings (neti'fim, pendant/drop earrings), bracelets (hasherot, possibly arm bracelets or wrist-bands), veils (hare'alot, the long gossamer shawls). The archaeological record from Iron Age Judah confirms an extensive luxury goods industry serving the urban elite — gold and silver jewelry, faience beads, ivory carvings — consistent with the social stratification Isaiah addresses. The removal of these items signals not merely fashion change but the economic and social collapse of the class that wore them.</p>",
    "20": "<p>'The turbans, the armlets, the sashes, the perfume bottles, and the lucky charms' — turbans (hapeerot, the ornamental head-coverings), armlets (hatsso'adot, ankle-chain step-adjusters or upper-arm ornaments), sashes (kittot, the broad ornamental belt over the outer robe), perfume bottles (bate hannefesh, houses/containers of soul/fragrance — small flask pendants worn around the neck containing fragrant ointments), and lucky charms (helechashim, the whisper-amulets — small inscribed objects worn to ward off evil spirits). The combination of fashion items and protective magic in the same list reflects the syncretism of Israelite practice in the 8th century.</p>",
    "21": "<p>'The signet rings and the nose rings' — signet rings (hatabbaot, the seal-rings used to authenticate documents and designate ownership), and nose rings (nezem ha'af, the nose ring worn through the septum). Signet rings were marks of authority and identity (Gen 41:42: Pharaoh puts his ring on Joseph's finger; Jer 22:24: Jehoiachin as YHWH's signet ring). Nose rings were bridal jewelry (Gen 24:47: the ring on Rebekah's nose) and status markers. Even these instruments of identity and authentication will be removed — the elite's very identity markers stripped away.</p>",
    "22": "<p>'The holiday garments, the capes, the wraps, and the purses' — holiday garments (machalashot, festival clothing — clothing worn specifically for sacred occasions), capes (hama'atafot, the large outer wraps), wraps (hamitpachot, the shawls or hair-covering cloths), and purses (hacharitim, the small bags or reticules). The holiday garments are particularly notable: stripping them signals the end of festival celebration — the appointed times (mo'adim) that YHWH declared he hates (1:14) will no longer be celebrated, not because the women chose to stop but because the social context that enabled them will be destroyed.</p>",
    "23": "<p>'The polished mirrors, the linen tunics, the tiaras, and the full-length veils' — polished mirrors (hageligyonim, the metal mirrors — ancient mirrors were polished bronze or copper), linen tunics (hassedinim, fine linen undergarments — Egyptian linen was luxury imported goods), tiaras (hatsenifot, the ornamental turbans or diadems worn at the top of the head — the same term is used for the high priest's headpiece in Exod 28:4), and full-length veils (haradidim, the large outer covering veil). The tiaras close the catalogue with the most elevated accessory — the symbolic crown — and its removal signals the end of royal pretension.</p>",
    "24": "<p>'Instead of sweet perfume there will be a stench; instead of a sash, a rope; instead of styled hair, a shaved head; instead of a fine robe, a garment of sackcloth; and instead of beauty, a branding scar' — the five-fold reversal catalogue (tachat/instead of...): five luxury items replaced by five shame-markers. Perfume/stench, sash/rope, styled hair/shaved head, fine robe/sackcloth, beauty/branding scar. Each reversal corresponds to a mode of disgrace: the stench of unburied dead or siege conditions; the rope of a prisoner or a captive (instead of the belt of dignity); the shaved head of mourning or shame (captives were shaved by conquerors); sackcloth as mourning dress; and the branding scar (ki, the cauterized mark) of a slave or prisoner of war.</p>",
    "25": "<p>'Your men will fall by the sword, your warriors in the heat of battle' — the military defeat that will produce the social conditions described in vv. 24-26. 'Your men' (mete'ayich, your men — addressed to the feminine Zion) and 'your warriors' (giborateyich, your mighty ones — grammatically feminine) will fall in battle. The military catastrophe produces the social inversion of ch. 3: women are left ruling (v. 12 implied), searching for any man with a robe (4:1), and grieving at the city gate (v. 26). The Assyrian and later Babylonian campaigns against Judah produced exactly this demographic catastrophe — massive male casualties and deportations.</p>",
    "26": "<p>'Her city gates will mourn and grieve; she will sit desolate on the ground' — Jerusalem personified as a woman sitting desolate (niqtah, emptied/cleaned out) on the ground. The gates 'mourning and grieving' (ve'anu vedalu, they lament and mourn) anthropomorphize the very architecture: the city gates were the centers of commerce, justice, and social life (Ruth 4:1; Job 29:7; Prov 31:23); their mourning signals the total cessation of normal urban life. The image of a woman sitting desolate on the ground is the posture of the abandoned/bereaved wife (Lam 1:1: 'How deserted lies the city, once so full of people! How like a widow is she'). Lamentations develops this image at length.</p>"
  },
  "4": {
    "1": "<p>'In that day seven women will grab hold of one man, saying: \"We will provide our own food and clothing — just let us bear your name and remove our disgrace\"' — the consequence of the military catastrophe narrated in 3:25 (men falling by the sword): the extreme gender imbalance of war casualties leaves seven women to one man. In the ancient world, marriage required a husband to provide food and clothing (Exod 21:10 — these were the wife's legal rights); here the desperate women waive this right, asking only for the man's name (to remove the social shame of unmarried status and childlessness). 'Remove our disgrace' (asof cherpatenu, gather away our reproach) — childlessness was the social shame in ancient Israelite culture (cf. Rachel's cry in Gen 30:23; Hannah's in 1 Sam 1:11).</p>",

    "2": "<p>'In that day the Branch of the LORD will be beautiful and glorious, and the produce of the land will be the pride and splendour of those of Israel who have survived' — the abrupt transition from the judgment oracle (ch. 3) to the salvation oracle: after the purging, the restored remnant will celebrate YHWH's Branch. 'The Branch of the LORD' (tsemach Yhwh) is the first use of this messianic title in the OT. In later prophets: Jer 23:5 ('I will raise up to David a righteous Branch'); 33:15; Zech 3:8 ('my servant, the Branch') and 6:12 ('the man whose name is the Branch'). Whether 'Branch' here refers primarily to agricultural produce ('the fruit of the land will be the pride') or to a messianic figure is a classic interpretive question — the text may hold both.</p>",
    "3": "<p>'Everyone who remains in Zion and is left in Jerusalem will be called holy — everyone enrolled among the living in Jerusalem' — the holiness of the remnant: those who survive the purging judgment will be designated 'holy' (qadosh) — set apart for YHWH. 'Enrolled among the living in Jerusalem' (hakkathuv lechayyim birushalayyim, written for life in Jerusalem) introduces the imagery of the divine enrollment register — the Book of Life. Exod 32:32-33 (Moses asking to be blotted from YHWH's book if Israel cannot be forgiven), Ps 69:28, Dan 12:1, and Rev 21:27 (only those written in the Lamb's book of life enter the New Jerusalem) all develop this image of divine registration as the determinant of eschatological survival.</p>",
    "4": "<p>'This will come about when the Lord has washed away the filth of the women of Zion and rinsed the blood from the midst of Jerusalem by a spirit of judgment and by a spirit of fire' — the purification conditions: washing (rachats) and rinsing (shataph) the filth (tso'ah, excrement/filth) of Zion's women (the proud women of 3:16-24) and the blood of Jerusalem. 'By a spirit of judgment and by a spirit of fire' (beruach mishpat uveruach ba'er) — the divine Spirit (ruach) as the agent of both legal verdict (mishpat) and consuming fire (ba'er). The Spirit both judges (determines guilt) and purges (burns away the unclean). This anticipates the Pentecostal Spirit of Acts 2 described as fire (Acts 2:3-4).</p>",
    "5": "<p>'Then the LORD will create over every dwelling-place on Mount Zion and over all her gatherings a cloud by day, and smoke with the glow of flaming fire by night; for a covering canopy will rest over all the glory' — the return of the Exodus theophanic cloud: the pillar of cloud by day and fire by night that accompanied Israel in the wilderness (Exod 13:21-22; 40:34-38: the cloud filling the tabernacle when YHWH took up residence). Now YHWH will recreate this presence-sign over all of Zion — not just the tabernacle/temple but 'every dwelling-place' (kol-makhon). The 'covering canopy' (chuppah, wedding canopy/marriage canopy) suggests the eschatological renewal of the YHWH-Israel marriage covenant, with the divine presence as the bridal covering over the whole community.</p>",
    "6": "<p>'There will be a shelter for shade from the heat of the day, a refuge and hiding place from storm and rain' — the practical blessing of the divine covering. The four threats: heat of day (chorev, the scorching summer heat), storm (zerem, violent rainstorm), and rain (matar) — the full range of Mediterranean climate dangers. YHWH as shelter and shade (tsil, shadow) from the sun is a recurring Psalms metaphor (Ps 91:1: 'under the shadow of the Almighty'; 121:5: 'the LORD watches over you — the LORD is your shade at your right hand'). The chapter moves from the stripping of luxury items (3:18-24) to the gift of YHWH's own covering (4:5-6) — replacing human ornament with divine shelter.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
